__attribute__((opencl_kernel))
__attribute__((opencl_global_work_dim(1)))
void findK(
    __attribute__((opencl_arg(0))) long maxheight,
    __attribute__((opencl_arg(1))) __global const knode *knodes,
    __attribute__((opencl_arg(2))) long knodes_elem,
    __attribute__((opencl_arg(3))) __global const record *records,
    __attribute__((opencl_arg(4))) __global long *currKnode,
    __attribute__((opencl_arg(5))) __global long *offset,
    __attribute__((opencl_arg(6))) __global const int *keys,
    __attribute__((opencl_arg(7))) __global record *ans
) {
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int i;
    long current_offset;

    current_offset = currKnode[bid];

    for (i = 0; i < maxheight; i++) {
        if (thid < knodes[current_offset].num_keys - 1) {
            if ((knodes[current_offset].keys[thid] <= keys[bid]) && (knodes[current_offset].keys[thid + 1] > keys[bid])) {
                if (knodes[current_offset].indices[thid] < knodes_elem) {
                    current_offset = knodes[current_offset].indices[thid];
                }
            }
        }
    }

    currKnode[bid] = current_offset;
    offset[bid] = current_offset;

    if (thid < knodes[current_offset].num_keys) {
        if (knodes[current_offset].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[current_offset].indices[thid]].value;
        }
    }
}

